create table pipeline_config
(
    id              integer generated by default as identity
        primary key,
    name            varchar(255)             not null,
    description     text,
    pipeline_config jsonb                    not null,
    user_id         varchar(255)             not null,
    del_flag        boolean                  not null,
    created_at      timestamp with time zone not null,
    updated_at      timestamp with time zone not null
);

alter table pipeline_config
    owner to myscale_kb_backend;

create index idx_pipeline_config_name
    on pipeline_config (name);

create index idx_pipeline_config_user_id
    on pipeline_config (user_id);

