": 1024, "tensor_parallel_size": 1, "pipeline_parallel_size": 8}], "vllm_used": true, "input_file": "demos/demos_result/math/pipeline_Q/Corrected_step0.jsonl", "model_path": "/root/workspace/culfjk4p420c73amv510/herunming/DataFlow/ckpr/models/Qwen/Qwen2.5-0.5B-Instruct", "output_key": "unused", "num_prompts": 2, "output_file": "demos/demos_result/math/pipeline_Q/generated_step1.jsonl", "requires_gpu": true, "system_prompt": "", "generator_type": "local"}}, {"id": "node3", "name": "MathProblemFilter", "type": "processor", "config": {"keys": "text", "use_hf": false, "api_args": {"api_url": "http://123.129.219.111:3000/v1/chat/completions", "mode_test": true, "model_name": "gpt-4o"}, "formatter": "TextFormatter", "max_score": 1, "min_score": 0, "input_file": "demos/demos_result/math/pipeline_Q/generated_step1.jsonl", "max_worker": 10, "output_file": "demos/demos_result/math/pipeline_Q/Corrected_step2.jsonl", "dependencies": ["text"], "requires_gpu": false, "model_cache_path": "../ckpt", "input_question_key": "instruction"}}, {"id": "node4", "name": "QuestionDifficultyClassifier", "type": "generator", "config": {"input_key": "instruction", "vllm_args": [{"seed": 25147, "top_k": 30, "top_p": 0.9, "max_tokens": 2048, "temperature": 0.6, "max_model_len": 1024, "tensor_parallel_size": 1, "pipeline_parallel_size": 8}], "vllm_used": true, "input_file": "demos/demos_result/math/pipeline_Q/Corrected_step2.jsonl", "model_path": "/root/workspace/culfjk4p420c73amv510/herunming/DataFlow/ckpr/models/Qwen/Qwen2.5-0.5B-Instruct", "output_key": "question_difficulty", "output_file": "demos/demos_result/math/pipeline_Q/difficultyclassified_step3.jsonl", "requires_gpu": true, "system_prompt": "", "generator_type": "local"}}, {"id": "node5", "name": "QuestionCategoryClassifier", "type": "generator", "config": {"input_key": "instruction", "vllm_args": [{"seed": 25147, "top_k": 30, "top_p": 0.9, "max_tokens": 2048, "temperature": 0.6, "max_model_len": 1024, "tensor_parallel_size": 1, "pipeli